// Build a lookup object so we can quickly check whether a reminder
// has already been sent for a given invoice + stage combination.
// Key format: "invoiceId_stage" e.g. "a1b2c3_7"
// Value: true (we only care whether the key exists)

const logRows = $input.all();
const lookup = {};

for (const row of logRows) {
  const invoiceId = row.json['Invoice ID'];
  const stage = row.json['Stage'];

  if (invoiceId && stage) {
    const key = `${invoiceId}_${stage}`;
    lookup[key] = true;
  }
}

return [{ json: { lookup } }];

// Filter invoices to only those that are overdue (due date has passed).
// Also calculate how many days overdue each invoice is.

const today = new Date();
today.setHours(0, 0, 0, 0);

const invoices = $input.first().json.data;
const overdueInvoices = [];

for (const invoice of invoices) {
  if (!invoice.due_date) continue;

  const dueDate = new Date(invoice.due_date);
  dueDate.setHours(0, 0, 0, 0);

  if (dueDate < today) {
    const msPerDay = 1000 * 60 * 60 * 24;
    const daysOverdue = Math.floor((today - dueDate) / msPerDay);

    overdueInvoices.push({
      json: {
        invoiceId:     invoice.id,
        invoiceNumber: invoice.number,
        clientName:    invoice.client?.name ?? 'Customer',
        clientEmail:   invoice.client?.contacts?.[0]?.email ?? null,
        amount:        invoice.balance,
        dueDate:       invoice.due_date,
        daysOverdue,
      }
    });
  }
}

return overdueInvoices;

// Stages triggered at these overdue thresholds (days):
// Stage 1  → day 1–6
// Stage 7  → day 7–13
// Stage 14 → day 14–29
// Stage 30 → day 30+
// Each stage is sent once; lookup prevents duplicates.

const STAGES = [1, 7, 14, 30];
const { lookup } = $('Build Log Lookup').first().json;
const remindersToSend = [];

for (const item of $input.all()) {
  const invoice = item.json;

  if (!invoice.clientEmail) continue;

  for (const stage of STAGES) {
    if (invoice.daysOverdue < stage) continue;

    const key = `${invoice.invoiceId}_${stage}`;
    if (lookup[key]) continue;

    remindersToSend.push({ json: { ...invoice, stage } });
  }
}

return remindersToSend;

// Stage tones:
// Stage 1  → friendly nudge
// Stage 7  → polite follow-up
// Stage 14 → direct request
// Stage 30 → final notice

const results = [];

for (const item of $input.all()) {
  const invoice = item.json;

  const formattedAmount = `£${parseFloat(invoice.amount).toFixed(2)}`;
  const formattedDueDate = new Date(invoice.dueDate).toLocaleDateString('en-GB', {
    day: 'numeric', month: 'long', year: 'numeric'
  });

  const templates = {
    1: {
      subject: `Payment reminder — Invoice ${invoice.invoiceNumber}`,
      body: `<p>Hi ${invoice.clientName},</p>
<p>Just a quick note to let you know that invoice ${invoice.invoiceNumber} for ${formattedAmount} was due on ${formattedDueDate}.</p>
<p>If you've already arranged payment, please ignore this message. If you have any questions, just reply and we'll be happy to help.</p>
<p>Thanks,<br>Observe Automation</p>`
    },
    7: {
      subject: `Follow-up: Invoice ${invoice.invoiceNumber} now 7 days overdue`,
      body: `<p>Hi ${invoice.clientName},</p>
<p>We're following up on invoice ${invoice.invoiceNumber} for ${formattedAmount}, which was due on ${formattedDueDate} and is now 7 days overdue.</p>
<p>Could you let us know when we can expect payment, or get in touch if there's anything you need from us?</p>
<p>Thanks,<br>Observe Automation</p>`
    },
    14: {
      subject: `Invoice ${invoice.invoiceNumber} — payment now 14 days overdue`,
      body: `<p>Hi ${invoice.clientName},</p>
<p>Invoice ${invoice.invoiceNumber} for ${formattedAmount} is now 14 days overdue (original due date: ${formattedDueDate}).</p>
<p>Please arrange payment at your earliest convenience, or contact us if there is an issue we should be aware of.</p>
<p>Regards,<br>Observe Automation</p>`
    },
    30: {
      subject: `Final notice — Invoice ${invoice.invoiceNumber}`,
      body: `<p>Hi ${invoice.clientName},</p>
<p>This is a final notice regarding invoice ${invoice.invoiceNumber} for ${formattedAmount}, which is now 30 days overdue.</p>
<p>Please contact us within 5 working days to arrange payment or discuss the outstanding balance.</p>
<p>Regards,<br>Observe Automation</p>`
    }
  };

  const template = templates[invoice.stage];

  results.push({
    json: {
      ...invoice,
      emailSubject: template.subject,
      emailBody:    template.body,
    }
  });
}

return results;
